    # Stub text layout using CoreText via basic measurement
    class TextSetting:
        def __init__(self, start=0, end=0, font='', slant='NORMAL', weight='NORMAL',
                     line_num=-1, color=None, is_new_line=False, **kwargs):
            self.start = start
            self.end = end
            self.font = font
            self.slant = slant
            self.weight = weight
            self.line_num = line_num
            self.color = color
            self.is_new_line = is_new_line

    def text2svg(settings, size, line_spacing, disable_liga, file_name,
                 START_X=0, START_Y=0, width=600, height=400, orig_text='',
                 pango_width=None):
        """Render text to SVG using <path> elements (manim SVGMobject compatible).
        Uses <rect> elements for each character since we can't extract font
        outlines without Pango on iOS. Each character = colored rectangle."""
        import os
        text = str(orig_text)
        if not text.strip():
            text = " "
        fs = max(size * 10, 12)
        char_w = fs * 0.55
        char_h = fs * 0.85
        # Get per-character colors from settings
        color_map = {}
        default_color = "white"
        if settings and hasattr(settings[0], 'start'):
            for s in settings:
                c = getattr(s, 'color', None) or default_color
                for i in range(s.start, min(s.end, len(text))):
                    color_map[i] = c
        # Build <rect> elements for each visible character
        rects = []
        x = float(START_X)
        y = float(START_Y) + fs * 0.1
        for i, ch in enumerate(text):
            if ch in (' ', '\t'):
                x += char_w
                continue
            if ch == '\n':
                x = float(START_X)
                y += char_h + fs * 0.3
                continue
            fill = color_map.get(i, default_color)
            rw = char_w * 0.78
            rh = char_h
            rects.append(f'<rect x="{x:.1f}" y="{y:.1f}" width="{rw:.1f}" height="{rh:.1f}" fill="{fill}" rx="1"/>')
            x += char_w
        svg_w = max(float(width), x + float(START_X))
        svg_h = max(float(height), y + char_h + fs * 0.3)
        svg = (f'<svg xmlns="http://www.w3.org/2000/svg" '
               f'width="{svg_w:.0f}" height="{svg_h:.0f}" '
               f'viewBox="0 0 {svg_w:.0f} {svg_h:.0f}">'
               + ''.join(rects) +
               '</svg>')
        if file_name:
            os.makedirs(os.path.dirname(str(file_name)) or '.', exist_ok=True)
            with open(str(file_name), 'w') as fobj:
                fobj.write(svg)
            return str(file_name)
        return svg

    def markup2svg(text, font='', slant='NORMAL', weight='NORMAL', size=1,
                   _placeholder=None, disable_ligatures=False, file_name='',
                   START_X=0, START_Y=0, width=600, height=400, **kwargs):
        """Render markup text to SVG using <rect> elements (same as text2svg)."""
        import re, os
        plain = re.sub(r'<[^>]+>', '', str(text))
        # Reuse text2svg logic with a fake settings list
        settings = [TextSetting(start=0, end=len(plain), font=font or '', color='white')]
        return text2svg(settings, size, 0, disable_ligatures, file_name,
                       START_X, START_Y, width, height, plain)

